import type { 
  Commit, 
  Binary, 
  Run, 
  EnrichedBenchmarkResult, 
  DiffTableRow, 
  PythonVersionFilterOption,
  BenchmarkUpload,
  MetricKey
} from './types';

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000';

class ApiError extends Error {
  constructor(public status: number, message: string) {
    super(message);
    this.name = 'ApiError';
  }
}

async function apiRequest<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
  const url = `${API_BASE_URL}${endpoint}`;
  
  const response = await fetch(url, {
    headers: {
      'Content-Type': 'application/json',
      ...options.headers,
    },
    ...options,
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new ApiError(response.status, `API Error: ${response.status} ${errorText}`);
  }

  return response.json();
}

export const api = {
  // Commits
  async getCommits(skip = 0, limit = 100): Promise<Commit[]> {
    return apiRequest(`/api/commits?skip=${skip}&limit=${limit}`);
  },

  async getCommit(sha: string): Promise<Commit> {
    return apiRequest(`/api/commits/${sha}`);
  },

  // Binaries
  async getBinaries(): Promise<Binary[]> {
    return apiRequest('/api/binaries');
  },

  async getBinary(binaryId: string): Promise<Binary> {
    return apiRequest(`/api/binaries/${binaryId}`);
  },

  // Runs
  async getRuns(params: {
    commitSha?: string;
    binaryId?: string;
    skip?: number;
    limit?: number;
  } = {}): Promise<Run[]> {
    const searchParams = new URLSearchParams();
    if (params.commitSha) searchParams.set('commit_sha', params.commitSha);
    if (params.binaryId) searchParams.set('binary_id', params.binaryId);
    if (params.skip) searchParams.set('skip', params.skip.toString());
    if (params.limit) searchParams.set('limit', params.limit.toString());
    
    return apiRequest(`/api/runs?${searchParams.toString()}`);
  },

  // Benchmark Results
  async getBenchmarkResults(params: {
    benchmarkName?: string;
    binaryId?: string;
    pythonMajor?: number;
    pythonMinor?: number;
    skip?: number;
    limit?: number;
  } = {}): Promise<EnrichedBenchmarkResult[]> {
    const searchParams = new URLSearchParams();
    if (params.benchmarkName) searchParams.set('benchmark_name', params.benchmarkName);
    if (params.binaryId) searchParams.set('binary_id', params.binaryId);
    if (params.pythonMajor) searchParams.set('python_major', params.pythonMajor.toString());
    if (params.pythonMinor) searchParams.set('python_minor', params.pythonMinor.toString());
    if (params.skip) searchParams.set('skip', params.skip.toString());
    if (params.limit) searchParams.set('limit', params.limit.toString());
    
    return apiRequest(`/api/benchmark-results?${searchParams.toString()}`);
  },

  // Diff Table
  async getDiffTable(commitSha: string, binaryId: string, metricKey: MetricKey = 'high_watermark_bytes'): Promise<DiffTableRow[]> {
    const searchParams = new URLSearchParams({
      commit_sha: commitSha,
      binary_id: binaryId,
      metric_key: metricKey,
    });
    
    return apiRequest(`/api/diff?${searchParams.toString()}`);
  },

  // Python Versions
  async getPythonVersions(): Promise<PythonVersionFilterOption[]> {
    return apiRequest('/api/python-versions');
  },

  // Upload
  async uploadBenchmarkResults(data: BenchmarkUpload): Promise<{ message: string; run_id: string; results_created: number; result_ids: string[] }> {
    return apiRequest('/api/upload', {
      method: 'POST',
      body: JSON.stringify(data),
    });
  },
};

export { ApiError };